mapper.select:
SELECT ci.sku_id, sku.spu_id, sku.sku_code, spu.spu_code, spu.name AS product_name, c.name AS category_name, co.name AS color, so.code AS size, sku.sale_price, ci.quantity, spu.main_image_url, sku.status AS sku_status, spu.status AS spu_status, COALESCE(inv.available_stock, 0) AS available_stock FROM cart_item ci JOIN product_sku sku ON sku.id = ci.sku_id JOIN product_spu spu ON spu.id = sku.spu_id JOIN category c ON c.id = spu.category_id JOIN color co ON co.id = sku.color_id JOIN size_option so ON so.id = sku.size_id LEFT JOIN inventory inv ON inv.sku_id = sku.id WHERE ci.user_id = #{userId} AND ci.sku_id IN
#{skuId}
ORDER BY ci.id ASC
